def migrate_assigned_to_to_taskassignment(apps, schema_editor):
    Task = apps.get_model("core", "Task")
    TaskAssignment = apps.get_model("core", "TaskAssignment")
    for task in Task.objects.all():
        assigned_id = getattr(task, "assigned_to_id", None)
        if assigned_id:
            try:
                TaskAssignment.objects.create(task_id=task.id, assignee_id=assigned_id)
            except Exception:
                pass


def reverse_migrate_assigned_to(apps, schema_editor):
    Task = apps.get_model("core", "Task")
    TaskAssignment = apps.get_model("core", "TaskAssignment")
    for task in Task.objects.all():
        task_assignment = TaskAssignment.objects.filter(task_id=task.id).first()
        if task_assignment:
            task.assigned_to_id = task_assignment.assignee_id
            task.save(update_fields=["assigned_to_id"])


