def create_materialized_views(apps, schema_editor):
    if schema_editor.connection.vendor != "postgresql":
        return
    schema_editor.execute(
        """
        CREATE MATERIALIZED VIEW IF NOT EXISTS core_timeentry_daily_totals AS
        SELECT
            user_id,
            DATE(start_datetime) AS day,
            SUM(duration) AS total_duration
        FROM core_timeentry
        GROUP BY user_id, DATE(start_datetime);

        CREATE UNIQUE INDEX IF NOT EXISTS idx_daily_totals_user_day
        ON core_timeentry_daily_totals (user_id, day);

        CREATE MATERIALIZED VIEW IF NOT EXISTS core_project_monthly_totals AS
        SELECT
            project_id,
            user_id,
            DATE_TRUNC('month', start_datetime)::date AS month_start,
            SUM(duration) AS total_duration
        FROM core_timeentry
        GROUP BY project_id, user_id, DATE_TRUNC('month', start_datetime)::date;

        CREATE UNIQUE INDEX IF NOT EXISTS idx_monthly_totals_project_user_month
        ON core_project_monthly_totals (project_id, user_id, month_start);
        """
    )


